import React, { useState, useEffect } from 'react';
import {
  Container,
  Grid,
  Card,
  CardContent,
  CardMedia,
  Typography,
  Button,
  Box,
  CircularProgress,
} from '@mui/material';
import axios from 'axios';

function Pitches() {
  const [pitches, setPitches] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchPitches = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/pitches');
        setPitches(response.data);
        setLoading(false);
      } catch (err) {
        setError('Failed to fetch pitches');
        setLoading(false);
      }
    };

    fetchPitches();
  }, []);

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Container>
        <Typography color="error" align="center" sx={{ mt: 4 }}>
          {error}
        </Typography>
      </Container>
    );
  }

  return (
    <Container sx={{ py: 4 }}>
      <Typography variant="h4" component="h1" gutterBottom align="center">
        Available Pitches
      </Typography>
      <Grid container spacing={4}>
        {pitches.map((pitch) => (
          <Grid item key={pitch.pitch_id} xs={12} sm={6} md={4}>
            <Card>
              <CardMedia
                component="img"
                height="200"
                image={pitch.image_url || 'https://via.placeholder.com/300x200?text=Cricket+Pitch'}
                alt={pitch.pitch_name}
              />
              <CardContent>
                <Typography gutterBottom variant="h5" component="h2">
                  {pitch.pitch_name}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {pitch.description}
                </Typography>
                <Typography variant="h6" color="primary" sx={{ mt: 2 }}>
                  ₹{pitch.price_per_hour}/hour
                </Typography>
                <Button
                  variant="contained"
                  color="primary"
                  fullWidth
                  sx={{ mt: 2 }}
                  onClick={() => {/* TODO: Implement booking functionality */}}
                >
                  Book Now
                </Button>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
}

export default Pitches;
